sys_script_fix.script:
// Using this INT variable select how long the month period would be for generation
// In this case random date will be generated in between 3 months
var selectMonth = gs.getProperty("month_period_selection");
//var selectMonth = 3;

// Variable for the generated date
var randomDate;

// Set a threshold on how many records would you like to generate per device
var recordNumberMax = gs.getProperty("record_number_max");
//var recordNumberMax = 35;
var recordNumberMin = gs.getProperty("record_number_min");
//var recordNumberMin = 15;

// Variables for the costs generation
var generatePaid;
var generateOperationalCost;
var operationalReturn;

function generateRandomDate() {
    // Get the current date
    var currentDate = new Date();

    // Calculate the date based on a selected period variable 'selectMonth'
    var monthPeriod = new Date();
    monthPeriod.setMonth(currentDate.getMonth() - selectMonth);

    // Generate a random timestamp between now and three months ago
    var randomTimestamp = new Date(
        monthPeriod.getTime() + Math.random() * (currentDate.getTime() - monthPeriod.getTime())
    );

    // Format the date as "YYYY-MM-DD HH:mm:ss"
    var year = randomTimestamp.getFullYear();
    var month = ('0' + (randomTimestamp.getMonth() + 1)).slice(-2); // Month is zero-indexed
    var day = ('0' + randomTimestamp.getDate()).slice(-2);
    var hours = ('0' + randomTimestamp.getHours()).slice(-2);
    var minutes = ('0' + randomTimestamp.getMinutes()).slice(-2);
    var seconds = ('0' + randomTimestamp.getSeconds()).slice(-2);

    // Combine to get the formatted date string
    var formattedDate = year + '-' + month + '-' + day + ' ' + hours + ':' + minutes + ':' + seconds;

    return formattedDate;
}

function createDeviceCosts(box_ref, op_return, op_cost, paid, date) {
    var logs = new GlideRecord("u_ev_costs");
    logs.initialize();
    logs.u_ev_box = box_ref;
    logs.u_operational_return = op_return;
    logs.u_operational_cost = op_cost;
    logs.u_paid = paid;
	logs.u_operation_date = date;
    logs.insert();
}

// Generate FLOAT random number for the cost fields
function randomFloatCost(min, max) { // min and max included 
    return (Math.random() * (max - min) + min).toFixed(2);
}

// Generate INT random number for the cost record per device
function getRandomNumber(min, max) {
  return Math.floor(Math.random() * (max - min + 1)) + min;
}

function generateCosts(baseDeviceCost) {
	// Currency field is an Object so we need to change it to the float number with .00 fixed
	var baseCostFloat = parseFloat(baseDeviceCost.toString());
    generatePaid = randomFloatCost(20.00, 120.00);
    generateOperationalCost = randomFloatCost(baseCostFloat, 10.00);
    operationalReturn = (generatePaid - generateOperationalCost).toFixed(2);
}

var evDevice = new GlideRecord('u_ev_devices');
evDevice.addActiveQuery();
evDevice.query();

while (evDevice.next()) {
	var recordNumber = getRandomNumber(recordNumberMin, recordNumberMax);
    for (var i = 0; i < recordNumber; i++) {
        generateCosts(evDevice.u_single_use_cost);
		randomDate = generateRandomDate();
		/*
		// For debugging only!
		gs.log('Device sys id:' + evDevice.sys_id);
		gs.log('Operational Return ' + operationalReturn);
		gs.log('Operational Cost ' + generateOperationalCost);
		gs.log('Paid ' + generatePaid);
		gs.log("Date " + randomDate);
		*/
        createDeviceCosts(evDevice.sys_id, operationalReturn, generateOperationalCost, generatePaid, randomDate);
    }
}
